1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
16	
17	export const nextGeneration = (cells: Cell[]): Cell[] => {
18	  const liveKeys = new Set<string>(cells.map(keyOf));
19	
20	  const candidates = new Map<string, Cell>();
21	  for (const cell of cells) {
22	    candidates.set(keyOf(cell), cell);
23	    for (const neighbor of neighborsOf(cell)) {
24	      candidates.set(keyOf(neighbor), neighbor);
25	    }
26	  }
27	
28	  const countLiveNeighbors = (cell: Cell): number =>
29	    neighborsOf(cell).reduce(
30	      (count, neighbor) => count + (liveKeys.has(keyOf(neighbor)) ? 1 : 0),
31	      0,
32	    );
33	
34	  const result: Cell[] = [];
35	  for (const [key, cell] of candidates) {
36	    if (survives(liveKeys.has(key), countLiveNeighbors(cell))) {
37	      result.push(cell);
38	    }
39	  }
40	  return result;
41	};
