1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell due to underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells due to underpopulation", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged as a still life", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
18	  });
19	  it("should transform a vertical blinker into a horizontal blinker", () => {
20	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
21	    expect(result).toHaveLength(3);
22	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
23	  });
24	  it("should let a center cell survive when it has 2 live neighbors in a 3-in-row with extra", () => {
25	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
26	    expect(result).toHaveLength(3);
27	    expect(result).toEqual(expect.arrayContaining([[1, 0], [1, 1], [1, -1]]));
28	  });
29	  it("should kill the center cell of a full 3x3 due to overpopulation", () => {
30	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1], [2, 1], [0, 2], [1, 2], [2, 2]]);
31	    expect(result).not.toContainEqual([1, 1]);
32	  });
33	  it("should create a new cell via reproduction in an L-shape", () => {
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
35	    expect(result).toHaveLength(4);
36	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
37	  });
38	});
